#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    long long va = *(const long long *)a;
    long long vb = *(const long long *)b;
    if (va < vb) return -1;
    if (va > vb) return 1;
    return 0;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        long long D;
        scanf("%d %lld", &N, &D);
        long long *L = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &L[i]);
        }
        qsort(L, N, sizeof(long long), compare);
        int pairs = 0;
        for (int i = 0; i + 1 < N; ) {
            if (L[i + 1] - L[i] <= D) {
                ++pairs;
                i += 2;
            } else {
                ++i;
            }
        }
        printf("%d\n", pairs);
        free(L);
    }
    return 0;
}

